VALUES
  ('social-worker-moex-02636', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於皮亞傑（Piaget）結構取向的認知發展理論，下列敘述何者正確？', '["人類與生俱來的認知能力，以適應與組織二者最重要", "人類的認知能力是與生俱來的，但抽象及邏輯能力則是後天發展出來的", "人類的認知是循一定階段發展的，最終都會到達「具體運思期」", "皮亞傑的認知發展理論受到佛洛伊德（Freud）學說影響很大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02637', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於艾瑞克森（Erikson）心理社會發展的八個階段中，在各「時期」與各階段的「任務」和「重要事件」的 連結，下列何者正確？', '["「中年時期」＋「親密 對 孤立」＋「父母角色、創造力」", "「兒童早期（3歲-6歲）」＋「主動 對 罪惡感」＋「學校」", "「成年前期（青年期）」＋「生產 對 停滯」＋「愛情」", "「幼兒時期（18個月-3歲）」＋「自主 對 羞愧或懷疑」＋「如廁」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02638', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於「成人晚期」的發展特色陳述中，下列何者正確？', '["個體面對失落或死亡的重要人生議題，開始作生命的回顧", "個體的結晶智力（crystallized intelligence）隨著年齡增長而逐漸退化", "個體會經驗自我認定的變動期，採取「去幻象化」（de-illusionment）的態度", "個體面對「親密」與「孤立」的發展議題，開始檢視婚姻關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02639', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '團體對於人類行為具有很大的影響，所謂團體動力的主要內容不包含下列那一項？', '["引導成員行為的規範", "成員在團體內扮演適當的角色", "影響成員彼此溝通的模式", "成員彼此間的私交"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02640', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於注意力缺陷過動失調（ADHD）的敘述，下列何者正確？', '["在診斷上，依據學校老師的觀察，學童注意力無法持久、過度活潑，該學童應該就是有ADHD", "在性別的分布上，女童ADHD的流行率約為男童的3倍", "治療ADHD的藥物可以增加兒童的注意力，減少課堂上的干擾，但也會產生食慾減退和睡眠干擾的副 作用", "在ADHD的治療上，社區照顧比起藥物治療及行為治療還有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02641', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '皮亞傑（Piaget）曾比喻兒童的遊戲為「最可佩的社會機構（social institutions）」，下列關於兒童遊戲的 陳述中，何者錯誤？', '["以周遭環境做為遊戲的象徵，例如扮家家酒", "今日兒童沉迷於電腦網路和電動玩具的遊戲，有助於想像力及合作性的增進", "皮亞傑主張兒童遊戲可以練習並增進認知技巧", "5歲兒童的遊戲類型多屬於結交性和合作性的遊戲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02642', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在臺灣兒童虐待的通報事件中，下列那一類通報比例最高？', '["身體虐待", "精神虐待", "性虐待", "疏忽"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02643', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於生態系統理論的敘述，下列何者正確？', '["依據此理論，社會工作者常用生態圖來評估個人生活空間裡，衝突與支持兩股力量的交互作用", "微視系統指的就是一位青少年過於認同「八家將」的同儕團體，影響其在學校的成績表現", "鉅視系統指的是政府機構對個人系統的影響，雖不直接介入個人系統，但卻影響生活深遠", "在處遇上，既然微視系統是個人最直接的接觸，處遇時應由個人的系統介入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02644', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '支持系統是一種特殊形式的社會情境或脈絡，下列那一項是牽涉到血緣、宗教、法律、教育等制度性功 能而構成的支持系統網絡？', '["正式組織", "正式團體", "社會網絡", "自然協助者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02645', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Toseland與Rivas的看法，社會工作專業將團體區分為治療性團體與任務團體，關於此兩類團體，下 列敘述何者正確？', '["任務團體是為了回應團體成員的需求而設計的；治療團體回應的則是聚焦於團體", "任務團體的目標是為了成員的社會化；治療團體的目標則聚焦個人化", "任務團體設定程序以確保成員公平參與溝通；治療團體的程序則由成員引導", "任務團體和治療團體最終的目的，都是要協助團體成員採取行動改變所處情境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02646', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據 Adams等人的研究顯示，造成失智症照顧者憂鬱的最主要原因是：', '["僱用照顧人力", "哀傷與悲痛", "自信心降低", "照顧者使用的藥物無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02647', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作一向具有國際性的特質，隨著全球化的趨勢，國際社會工作的發展將被更加重視，而Gray與Fook 兩位學者在思考國際社會工作時提出應顧及四方面的緊張狀況，下列何者並非其緊張狀況之一？', '["專業化與非專業化：專業發展與非專業之間的衝突", "西方化與本土化：西方與對立的實務想法間之平衡", "多元主義與普世主義：對於內在的文化偏誤之意涵與回應", "全球化與在地化：全球化與在地化的趨勢同時發生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02648', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者對於藥物濫用者除了要尊重案主自決等項條件外，其實務原則有下列幾項，何者不在其中？', '["了解與成癮者有關的生物性、心理性與社會性因素", "了解治療的雙重目標是停止藥物與酒精使用，並恢復家庭、職場、社區的正常生活", "了解種族與族群、年齡、性別等個人特質因素對藥物濫用的盛行狀況", "運用策略強化個人的動機與社會支持使案主能完成處遇計畫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02649', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依兒童及少年收出養媒合服務者許可及管理辦法第 5 條，收出養媒合服務者應設置社會工作人員而再依 第20條的規定，收出養媒合服務者應定期召開督導會議，其社會工作人員每年應接受兒童及少年福利與 收出養相關課程在職訓練至少多少小時？', '["10小時", "12小時", "20小時", "25小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02650', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社區能力建構（community capacity building, CCB）是英國自90年代以來主要社區工作議題，學者Ellis 和Latif指出社區能力建構這個概念已成為英國新工黨對抗社區排除與落後地區重建的核心概念之一，而 所謂社區的能力，下列敘述何者錯誤？', '["建立一種可以進行公共事務討論的機制", "建立居民間的正式或非正式組織", "建立諮詢及交流機制", "建立居民向外求助的意識感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02651', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依馬上關懷急難救助作業要點第5條第2項有關實地訪查的成員，下列敘述何者錯誤？', '["核定機關之代表並兼訪視小組召集人", "村（里）長或村（里）幹事", "當地立案社會福利機構（團體）或普受社會大眾信賴公益團體之代表，社會福利機構（團體）應指派 社會工作人員為代表", "直轄市、縣（市）政府相關目的的事業主管機關代表或當地管區警員"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02652', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近些年來，在美國的社會工作從多元文化主義的觀點而逐漸發展出靈性照顧社會工作實務（spiritual-based social work），而影響此案的因素之一即是因美國總統曾於2001年啟動了信仰基礎的社會服務模式 （faith-based social service initiatives），其具體做法就是立法讓宗教機構或是採用宗教與社會工作協同合 作的機構，可以向聯邦政府爭取經費，同時也鼓勵公私部門基金投入宗教與社會工作協同合作的社會服 務，請問推動此案的總統為何人？', '["雷根總統", "柯林頓總統", "小布希總統", "歐巴馬總統"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02653', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依社會工作師法第16條，社會工作師執行業務時應撰製社會工作紀錄，其紀錄應由執業之機關、團體、 事務所保存，而前項紀錄保存年限不得少於幾年？', '["5年", "7年", "10年", "12年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02654', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依推動「高風險家庭關懷輔導處遇實施計畫」，其相關業務承辦單位的工作內容下列何者錯誤？', '["接受社會局（處）轉介個案不得無故拒絕，接案後應於7個上班日內進行初訪，並於1個月內向社會 局（處）回覆評估結果", "依本計畫內容提供相關服務，並應將個案資料建置於高風險家庭個案管理資訊系統", "運用家庭成員優點增進案家權能，協助脫離困境", "依個案狀況安排訪視之密度，輔以電話關懷協助案主，並做成紀錄備查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02655', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在實施受刑人家庭支持服務應涵蓋的面向有下列四項，何者錯誤？', '["協助受刑人家屬因應服刑者觸法所衍生之生活或法律危機，以避免一人犯罪全家受苦", "協助主要照顧者發揮親職功能，減少受刑人缺席對子女成長的負面影響", "協助家庭連結並擴展相關社會資源以因應經濟困難、社會孤立、子女乏人照顧等實質生活困境", "協助受刑人對於犯罪行為的自我承擔及悔過"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02656', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '敘事治療（narrative therapy）被認為是利用後現代理論觀點於社會工作實務的重要方式，其在實務運用上 的四個原則，下列何者不在其中？', '["把焦點放在形成服務使用者生活的敘事和描述", "把焦點放在協助個人面對問題、解決問題", "用生存、勇氣、責任和積極抵抗來重新建構自己的生命故事", "與案主形成平等且尊重的夥伴關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02657', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在面對服務案主的過程中常會碰到非自願性案主而造成工作上的困難，對此學者Trotter則提 出一個明確的、有效的整合干預模式來幫助這些案主，其方法有四項，下列何者錯誤？', '["社會工作者要清楚地、坦誠地、經常地討論其與案主在個案工作過程中的角色", "社會工作者要技巧地建立與案主的關係", "社會工作者要聚焦在示範，並且鼓勵案主符合社會價值觀的言談及行動", "社會工作者要採用任務中心的工作模式處理，設定任務來解決案主的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02658', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '優勢觀點（strength perspective）在社會工作理論及實務的討論和運用上普遍被肯定與接受，對於此觀點 下列敘述何者錯誤？', '["優勢觀點的服務目標是著重在問題的消弭", "優勢觀點聚焦在案主面對此情境中展現的能力與自尊，甚至超越障礙和問題後的成長與復原", "優勢觀點的服務過程是傾聽案主的聲音，發掘和充分運用其優勢達成其想望", "優勢觀點在處遇過程中，讓案主當指導者，而社會工作者為其夥伴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02659', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '隨著高齡化社會的到來，世界衛生組織（WHO）曾於2002年提出一個活躍老化（Active Aging）的概念及 老年健康政策擬定的主要架構。為了達到活躍老化的目標，WHO提出三大政策支柱，下列何者不在其中？', '["健康促進", "社會參與", "友善關懷", "社會安全"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02660', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近些年來，面對社會工作理論發展的趨向多元化及多樣性，而各理論在實務界的運用亦各有其利弊，因 此有學者指出社會工作理論在實務運用上有趨向折衷主義的取向和趨勢，而形成此現象的主要原因有四， 下列何者錯誤？', '["社會工作處遇模式的轉變趨勢", "案主問題情況的錯綜複雜", "社會工作實務績效和責信之要求", "社會工作者經常需要依法裁量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
